                # If we can't parse diagnosis time, include all prescriptions for this admission
                for drug in drugs:
                    if drug in drug_count:
                        drug_count[drug] += 1
                    else:
                        drug_count[drug] = 1
        else:
            # If no diagnosis charttime, include all prescriptions for this admission
            for drug in drugs:
                if drug in drug_count:
                    drug_count[drug] += 1
                else:
                    drug_count[drug] = 1

